package federation

import (
	"fmt"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/update"
)

// HandshakeResult is the outcome of validating a spoke's version handshake
// against the hub's own version + schema version.
type HandshakeResult struct {
	// Accept reports whether the registration should be accepted at all.
	Accept bool
	// Status is the SpokeStatus to record on accepted registrations:
	// StatusRegistered when fully compatible (heartbeat will move it to
	// StatusActive), or StatusDegraded when accepted-but-newer.
	Status SpokeStatus
	// Reason is a short, machine-readable code for the outcome — used as the
	// rejection reason on 4xx and as a degraded-status reason on accept.
	// Stable enum: "ok", "degraded_newer_minor",
	// "schema_mismatch", "ddx_major_mismatch", "missing_ddx_version",
	// "missing_schema_version", "invalid_ddx_version".
	Reason string
}

// Handshake validates a spoke's version handshake.
//
//   - schema_version must match the hub's schema version exactly. Anything
//     else is rejected ("schema_mismatch").
//   - ddx_version must parse as semver. Major version must match the hub.
//     A higher minor or patch on the spoke side accepts as StatusDegraded
//     ("degraded_newer_minor"). Equal-or-lower minors/patches accept as
//     StatusRegistered ("ok"). Mismatched majors are rejected
//     ("ddx_major_mismatch").
//
// Empty / unparseable inputs are rejected with descriptive reasons.
func Handshake(hubDDxVersion, hubSchemaVersion, spokeDDxVersion, spokeSchemaVersion string) HandshakeResult {
	if strings.TrimSpace(spokeSchemaVersion) == "" {
		return HandshakeResult{Reason: "missing_schema_version"}
	}
	if spokeSchemaVersion != hubSchemaVersion {
		return HandshakeResult{Reason: "schema_mismatch"}
	}
	if strings.TrimSpace(spokeDDxVersion) == "" {
		return HandshakeResult{Reason: "missing_ddx_version"}
	}
	hubParts, err := update.ParseVersion(hubDDxVersion)
	if err != nil {
		return HandshakeResult{Reason: fmt.Sprintf("invalid_hub_ddx_version:%v", err)}
	}
	spokeParts, err := update.ParseVersion(spokeDDxVersion)
	if err != nil {
		return HandshakeResult{Reason: "invalid_ddx_version"}
	}
	if spokeParts[0] != hubParts[0] {
		return HandshakeResult{Reason: "ddx_major_mismatch"}
	}
	// Same major, compare minor.patch. Any newer minor or patch on the spoke
	// side is "compatible-but-newer" → degraded.
	newer := spokeParts[1] > hubParts[1] ||
		(spokeParts[1] == hubParts[1] && spokeParts[2] > hubParts[2])
	if newer {
		return HandshakeResult{Accept: true, Status: StatusDegraded, Reason: "degraded_newer_minor"}
	}
	return HandshakeResult{Accept: true, Status: StatusRegistered, Reason: "ok"}
}
// Package federation defines the hub-side federation registry: state types,
// persistence, and reconciliation helpers. No HTTP layer here — that lands in
// later beads. The on-disk format carries a schema_version field for forward
// compatibility (see ADR-007 and FEAT-026).
package federation

import (
	"fmt"
	"time"
)

// CurrentSchemaVersion is the schema_version this build writes. Reading code
// must accept older versions and migrate; writing code always emits this.
const CurrentSchemaVersion = "1"

// SpokeStatus is the lifecycle/health status of a registered spoke.
//
// The states are:
//   - StatusRegistered: spoke has registered but no heartbeat has been observed yet.
//   - StatusActive:     last heartbeat is recent (the live/healthy state).
//   - StatusStale:      no heartbeat for ≥ 2 minutes.
//   - StatusOffline:    fan-out to the spoke failed (connection refused, unreachable).
//   - StatusDegraded:   version handshake accepted with minor/schema drift.
//
// The bead-level enum collapses ADR-007's split between compat_status and
// liveness into a single field for v1 persistence; richer surface fields can
// be added in later schema versions without breaking older readers.
type SpokeStatus string

const (
	StatusRegistered SpokeStatus = "registered"
	StatusActive     SpokeStatus = "active"
	StatusStale      SpokeStatus = "stale"
	StatusOffline    SpokeStatus = "offline"
	StatusDegraded   SpokeStatus = "degraded"
)

// Valid reports whether s is one of the known status values.
func (s SpokeStatus) Valid() bool {
	switch s {
	case StatusRegistered, StatusActive, StatusStale, StatusOffline, StatusDegraded:
		return true
	}
	return false
}

// SpokeRecord is one entry in the federation registry.
type SpokeRecord struct {
	NodeID        string      `json:"node_id"`
	Name          string      `json:"name"`
	URL           string      `json:"url"`
	DDxVersion    string      `json:"ddx_version,omitempty"`
	SchemaVersion string      `json:"schema_version,omitempty"`
	Capabilities  []string    `json:"capabilities,omitempty"`
	RegisteredAt  time.Time   `json:"registered_at"`
	LastHeartbeat time.Time   `json:"last_heartbeat"`
	Status        SpokeStatus `json:"status"`
}

// FederationRegistry is the persisted hub state.
type FederationRegistry struct {
	SchemaVersion string        `json:"schema_version"`
	Spokes        []SpokeRecord `json:"spokes"`
}

// NewRegistry returns an empty registry stamped with the current schema version.
func NewRegistry() *FederationRegistry {
	return &FederationRegistry{
		SchemaVersion: CurrentSchemaVersion,
		Spokes:        []SpokeRecord{},
	}
}

// FindSpoke returns the record for nodeID, or nil if absent.
func (r *FederationRegistry) FindSpoke(nodeID string) *SpokeRecord {
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == nodeID {
			return &r.Spokes[i]
		}
	}
	return nil
}

// UpsertSpoke inserts or replaces a spoke by NodeID. NodeID must be non-empty.
func (r *FederationRegistry) UpsertSpoke(rec SpokeRecord) error {
	if rec.NodeID == "" {
		return fmt.Errorf("federation: spoke node_id is required")
	}
	if rec.Status == "" {
		rec.Status = StatusRegistered
	}
	if !rec.Status.Valid() {
		return fmt.Errorf("federation: invalid spoke status %q", rec.Status)
	}
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == rec.NodeID {
			r.Spokes[i] = rec
			return nil
		}
	}
	r.Spokes = append(r.Spokes, rec)
	return nil
}

// RemoveSpoke removes a spoke by NodeID; reports whether it was present.
func (r *FederationRegistry) RemoveSpoke(nodeID string) bool {
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == nodeID {
			r.Spokes = append(r.Spokes[:i], r.Spokes[i+1:]...)
			return true
		}
	}
	return false
}

// SetStatus updates the status of a spoke and returns true on success. Refuses
// unknown status values so callers cannot silently corrupt persisted state.
func (r *FederationRegistry) SetStatus(nodeID string, status SpokeStatus) error {
	if !status.Valid() {
		return fmt.Errorf("federation: invalid status %q", status)
	}
	rec := r.FindSpoke(nodeID)
	if rec == nil {
		return fmt.Errorf("federation: spoke %q not found", nodeID)
	}
	rec.Status = status
	return nil
}

// ReconcileLiveness derives status purely from elapsed time since the last
// heartbeat for spokes whose status is currently in {registered, active,
// stale}. Statuses set externally (offline from fan-out failure, degraded from
// version handshake) are left alone — those are not time-driven.
//
//   - now - last_heartbeat <  staleAfter            → active
//   - now - last_heartbeat >= staleAfter            → stale
//
// A zero LastHeartbeat keeps a freshly-registered spoke in StatusRegistered
// until the first heartbeat is observed.
func (r *FederationRegistry) ReconcileLiveness(now time.Time, staleAfter time.Duration) {
	for i := range r.Spokes {
		s := &r.Spokes[i]
		switch s.Status {
		case StatusOffline, StatusDegraded:
			continue
		}
		if s.LastHeartbeat.IsZero() {
			s.Status = StatusRegistered
			continue
		}
		if now.Sub(s.LastHeartbeat) >= staleAfter {
			s.Status = StatusStale
		} else {
			s.Status = StatusActive
		}
	}
}

package federation

import (
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"sync"
)

// stateFileName is the on-disk filename, under XDG_DATA_HOME / ~/.local/share.
const stateFileName = "federation-state.json"

// fileMode is mode 0600: registry may carry spoke URLs and identity, so it is
// owner-readable only (FEAT-026 NFR).
const fileMode os.FileMode = 0o600

// dirMode for the parent directory.
const dirMode os.FileMode = 0o700

// writeMu serializes concurrent SaveStateTo calls within one process so
// tmpfile+rename does not race against itself. (Cross-process safety relies
// on rename atomicity.)
var writeMu sync.Mutex

// DefaultStatePath returns ~/.local/share/ddx/federation-state.json.
// Honors XDG_DATA_HOME when set, otherwise falls back to ~/.local/share.
func DefaultStatePath() (string, error) {
	if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
		return filepath.Join(xdg, "ddx", stateFileName), nil
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return "", fmt.Errorf("federation: cannot determine home directory: %w", err)
	}
	return filepath.Join(home, ".local", "share", "ddx", stateFileName), nil
}

// LoadState reads the registry from the default path.
func LoadState() (*FederationRegistry, error) {
	path, err := DefaultStatePath()
	if err != nil {
		return nil, err
	}
	return LoadStateFrom(path)
}

// SaveState writes the registry to the default path.
func SaveState(r *FederationRegistry) error {
	path, err := DefaultStatePath()
	if err != nil {
		return err
	}
	return SaveStateTo(path, r)
}

// LoadStateFrom reads the registry from path. Behavior:
//
//   - Missing file       → fresh empty registry stamped with CurrentSchemaVersion.
//   - Malformed JSON     → fresh empty registry; the corrupt file is renamed
//     to "<path>.corrupt-<ts>" so an operator can recover it.
//   - Unknown future     → loaded as-is; caller can inspect SchemaVersion and
//     schema_version       decide whether to refuse to write.
func LoadStateFrom(path string) (*FederationRegistry, error) {
	data, err := os.ReadFile(path)
	if errors.Is(err, os.ErrNotExist) {
		return NewRegistry(), nil
	}
	if err != nil {
		return nil, fmt.Errorf("federation: read state: %w", err)
	}

	var reg FederationRegistry
	if err := json.Unmarshal(data, &reg); err != nil {
		// Quarantine the corrupt file so it's not silently overwritten on the
		// next save, then return a fresh registry. This is the recovery path
		// the bead's "malformed-file recovery" AC asks for.
		_ = quarantineCorrupt(path)
		return NewRegistry(), nil
	}

	if reg.SchemaVersion == "" {
		// Pre-versioned files are treated as v1; future migrations would key
		// off the read SchemaVersion before this defaulting.
		reg.SchemaVersion = CurrentSchemaVersion
	}
	if reg.Spokes == nil {
		reg.Spokes = []SpokeRecord{}
	}
	return &reg, nil
}

// SaveStateTo writes the registry to path atomically: marshal → write tmpfile
// in the same directory → fsync → rename onto the target. The rename is
// atomic on POSIX filesystems, so a partially-written file is never visible.
func SaveStateTo(path string, r *FederationRegistry) error {
	if r == nil {
		return fmt.Errorf("federation: nil registry")
	}
	if r.SchemaVersion == "" {
		r.SchemaVersion = CurrentSchemaVersion
	}
	if r.Spokes == nil {
		r.Spokes = []SpokeRecord{}
	}

	writeMu.Lock()
	defer writeMu.Unlock()

	if err := os.MkdirAll(filepath.Dir(path), dirMode); err != nil {
		return fmt.Errorf("federation: mkdir: %w", err)
	}

	data, err := json.MarshalIndent(r, "", "  ")
	if err != nil {
		return fmt.Errorf("federation: marshal: %w", err)
	}

	tmp, err := os.CreateTemp(filepath.Dir(path), ".federation-state-*.json.tmp")
	if err != nil {
		return fmt.Errorf("federation: create tmpfile: %w", err)
	}
	tmpPath := tmp.Name()
	cleanup := func() { _ = os.Remove(tmpPath) }

	if _, err := tmp.Write(data); err != nil {
		_ = tmp.Close()
		cleanup()
		return fmt.Errorf("federation: write tmpfile: %w", err)
	}
	if err := tmp.Sync(); err != nil {
		_ = tmp.Close()
		cleanup()
		return fmt.Errorf("federation: fsync tmpfile: %w", err)
	}
	if err := tmp.Close(); err != nil {
		cleanup()
		return fmt.Errorf("federation: close tmpfile: %w", err)
	}
	if err := os.Chmod(tmpPath, fileMode); err != nil {
		cleanup()
		return fmt.Errorf("federation: chmod tmpfile: %w", err)
	}
	if err := os.Rename(tmpPath, path); err != nil {
		cleanup()
		return fmt.Errorf("federation: rename: %w", err)
	}
	return nil
}

func quarantineCorrupt(path string) error {
	info, err := os.Stat(path)
	if err != nil || info.IsDir() {
		return err
	}
	bak := fmt.Sprintf("%s.corrupt-%d", path, info.ModTime().UnixNano())
	return os.Rename(path, bak)
}
// Package serverreg provides fire-and-forget project registration with the
// ddx-server. CLI commands call TryRegisterAsync so the server always has an
// up-to-date project list. If no server is reachable the call is silently
// discarded — the CLI never depends on the server being available.
package serverreg

import (
	"bytes"
	"crypto/tls"
	"encoding/json"
	"net/http"
	"os"
	"path/filepath"
	"time"
)

const defaultServerURL = "https://localhost:7743"

// TryRegisterAsync fires off a project registration in a background goroutine
// and returns immediately. Errors are silently discarded.
func TryRegisterAsync(projectPath string) {
	url := resolveServerURL()
	if url == "" {
		return
	}
	go register(url, projectPath)
}

func register(serverURL, projectPath string) {
	body, err := json.Marshal(map[string]string{"path": projectPath})
	if err != nil {
		return
	}

	client := &http.Client{
		Timeout: 500 * time.Millisecond,
		// Accept self-signed certs — the server uses an auto-generated cert.
		Transport: &http.Transport{
			TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
		},
	}

	req, err := http.NewRequest(http.MethodPost, serverURL+"/api/projects/register", bytes.NewReader(body))
	if err != nil {
		return
	}
	req.Header.Set("Content-Type", "application/json")

	resp, err := client.Do(req)
	if err != nil {
		return
	}
	_ = resp.Body.Close()
}

// resolveServerURL returns, in order of preference:
//  1. DDX_SERVER_URL environment variable
//  2. URL from ~/.local/share/ddx/server.addr
//  3. https://localhost:7743 (default)
func resolveServerURL() string {
	if u := os.Getenv("DDX_SERVER_URL"); u != "" {
		return u
	}
	if u := readAddrFile(); u != "" {
		return u
	}
	return defaultServerURL
}

func readAddrFile() string {
	type addrFile struct {
		URL string `json:"url"`
	}
	dir := addrDir()
	data, err := os.ReadFile(filepath.Join(dir, "server.addr"))
	if err != nil {
		return ""
	}
	var af addrFile
	if err := json.Unmarshal(data, &af); err != nil {
		return ""
	}
	return af.URL
}

func addrDir() string {
	if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
		return filepath.Join(xdg, "ddx")
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return filepath.Join("/tmp", "ddx")
	}
	return filepath.Join(home, ".local", "share", "ddx")
}

